			for (i=0; i<sk_PKCS7_RECIP_INFO_num(rsk); i++)
				{
				ri=sk_PKCS7_RECIP_INFO_value(rsk,i);

				if (pkcs7_decrypt_rinfo(&ek, &eklen,
							ri, pkey) < 0)
